code = """import json
import re
import os

# load clinical JSON file from storage path
clinical_path = var_call_P2EfXGIsnENW0VYWQwsmtBWc
if isinstance(clinical_path, str) and os.path.exists(clinical_path):
    with open(clinical_path, 'r') as f:
        clinical_list = json.load(f)
else:
    # fallback if variable directly contains list
    clinical_list = var_call_P2EfXGIsnENW0VYWQwsmtBWc

# load mutation PASS participant list from storage variable
mut_list = var_call_esovDwwVeDTa2CUN0tpQgqkM
# mut_list is expected to be a list of dicts with ParticipantBarcode
mutated_set = set()
for item in mut_list:
    if isinstance(item, dict) and 'ParticipantBarcode' in item:
        mutated_set.add(item['ParticipantBarcode'].strip())

# process clinical records
barcode_hist = {}  # map barcode -> hist_type (first occurrence)
for rec in clinical_list:
    pd = rec.get('Patient_description','')
    if not pd or 'FEMALE' not in pd:
        continue
    hist = rec.get('histological_type')
    if not hist:
        continue
    hist = hist.strip()
    if hist == '' or hist == 'None':
        continue
    # extract TCGA barcode
    m = re.search(r'(TCGA[-A-Z0-9]+)', pd)
    if not m:
        continue
    barcode = m.group(1).strip()
    # map if not already present
    if barcode not in barcode_hist:
        barcode_hist[barcode] = hist

# build counts per histological type
counts = {}  # hist -> {'mut_true': int, 'mut_false': int}
for barcode, hist in barcode_hist.items():
    mutated = barcode in mutated_set
    if hist not in counts:
        counts[hist] = {'mut_true':0, 'mut_false':0}
    if mutated:
        counts[hist]['mut_true'] += 1
    else:
        counts[hist]['mut_false'] += 1

# compute totals and filter hist types with total > 10
filtered = {}
for hist, v in counts.items():
    total = v['mut_true'] + v['mut_false']
    if total > 10:
        filtered[hist] = {'mut_true': v['mut_true'], 'mut_false': v['mut_false'], 'total': total}

if len(filtered) == 0:
    result = {'error':'No histological categories with total > 10 after filtering.'}
    print('__RESULT__:')
    print(json.dumps(result))
else:
    # prepare observed matrix rows (for filtered hist types)
    hist_names = sorted(filtered.keys())
    obs = []
    for h in hist_names:
        obs.append([filtered[h]['mut_false'], filtered[h]['mut_true']])
    # compute row totals, col totals, grand total
    row_totals = [sum(r) for r in obs]
    col_totals = [sum(r[i] for r in obs) for i in range(2)]
    grand_total = sum(row_totals)
    # compute expected and chi2
    chi2 = 0.0
    for i, r in enumerate(obs):
        for j, o in enumerate(r):
            expected = row_totals[i] * col_totals[j] / grand_total if grand_total>0 else 0
            if expected > 0:
                chi2 += (o - expected)**2 / expected
    # build contingency list
    contingency_list = []
    for h in hist_names:
        contingency_list.append({'histological_type': h, 'mutated_false': filtered[h]['mut_false'], 'mutated_true': filtered[h]['mut_true'], 'total': filtered[h]['total']})
    result = {'chi2': chi2, 'grand_total': grand_total, 'included_hist_types': hist_names, 'contingency_table': contingency_list}
    print('__RESULT__:')
    print(json.dumps(result))"""

